區間數字個數 <p>給一個長度為 \(n\) 陣列，\(q\) 筆詢問 :</p> <ul> <li> <p>\(\text{query}(l,r,x):a_l,\ldots ,a_r\)，\(x\) 出現的次數</p> </li> <li> <p>\(\text{update}(i,x):\) 將 \(a_i=x\)</p> </li> </ul> <p>\(n,q\le 2\times 10^5,x\le 10^9\)</p> 思路 <p>（靜態）沒 update : vec[x] 放 \(a_i=x\) 的所有 \(x\)</p> <p>（動態）有 update : DS[x] 支援 </p> <ul> <li> <p>insert(i)</p> </li> <li> <p>erase(i)</p> </li> <li> <p>lower_bound(i)</p> </li> </ul> <p>使用 Treap 或 <code>pb_ds::tree</code></p> code <pre><code>// using pbds
tree&lt;pii,null_type,less&lt;pii&gt;,rb_tree_tag,tree_order_statistics_node_update&gt; T;
// update(i, x)
T.erase({a[i], i});
a[i] = x;
T.insert({a[i], i});
// query(l, r, x)
cout &lt;&lt; T.order_of_key(mk(id, r + 1)) - T.order_of_key(mk(id, l)); </code></pre> 資芽 OJ 794 — 區間絕對眾數 <p>輸入一個長度為 \(N\) 的正整數序列 \(a_1, \ldots, a_N\)，接下來有 \(Q\) 筆詢問。</p> <p>每筆詢問輸入 \(l_i, r_i\)，輸出區間 \([l_i, r_i]\) 的絕對眾數，若不存在請輸出 \(0\)。</p> <p>\(N, Q \leq 5 \times 10^5, 1 \leq a_i \leq 5 \times 10^5\)</p> 思路 <p> </p> code <pre><code>#include &lt;bits/stdc++.h&gt;
#include &lt;bits/extc++.h&gt;
#define int long long
#define pii pair&lt;int, int&gt;
#define pb push_back
#define mk make_pair
#define F first
#define S second
#define ALL(x) x.begin(), x.end()
using namespace std;
using namespace __gnu_pbds;
tree&lt;pii,null_type,less&lt;pii&gt;,rb_tree_tag,tree_order_statistics_node_update&gt; T;
const int INF = 2e18;
const int maxn = 5e5 + 5;
const int M = 1e9 + 7;
struct Node {
Node* lc = nullptr;
Node* rc = nullptr;
int l, r;
int id = -1, cnt = 0;
Node(int l, int r) : l(l), r(r) {}
void pull () {
if (lc-&gt;cnt == 0) {
id = rc-&gt;id;
cnt = rc-&gt;cnt;
return;
} if (rc-&gt;cnt == 0) {
id = lc-&gt;id;
cnt = lc-&gt;cnt;
return;
}
if (lc-&gt;id == rc-&gt;id) {
id = lc-&gt;id;
cnt = lc-&gt;cnt + rc-&gt;cnt;
} else {
if (lc-&gt;cnt &gt; rc-&gt;cnt) {
id = lc-&gt;id;
cnt = lc-&gt;cnt - rc-&gt;cnt;
} else {
id = rc-&gt;id;
cnt = rc-&gt;cnt - lc-&gt;cnt;
}
}
}
};
int n, q;
int a[maxn];
Node* build (int l, int r) {
Node* root = new Node(l, r);
if (l == r) {
root-&gt;id = a[l];
root-&gt;cnt = 1;
return root;
}
int mid = (l + r) / 2;
root-&gt;lc = build(l, mid);
root-&gt;rc = build(mid + 1, r);
root-&gt;pull();
return root;
}
pii query(const Node* root, int ql, int qr) {
if (qr &lt; root-&gt;l || root-&gt;r &lt; ql) return {-1, 0};
if (ql &lt;= root-&gt;l &amp;&amp; root-&gt;r &lt;= qr) {
return {root-&gt;id, root-&gt;cnt};
} pii tmp = {-1, 0};
if (ql &lt;= root-&gt;lc-&gt;r) {
pii ret = query(root-&gt;lc, ql, qr);
if (tmp.S == 0) {
tmp = ret;
} else if (ret.S != 0) {
if (ret.F == tmp.F) {
tmp.S += ret.S;
} else {
if (ret.S &gt; tmp.S) {
tmp.F = ret.F;
tmp.S = ret.S - tmp.S;
} else {
tmp.S = tmp.S - ret.S;
}
}
}
}
if (root-&gt;rc-&gt;l &lt;= qr) {
pii ret = query(root-&gt;rc, ql, qr);
if (tmp.S == 0) {
tmp = ret;
} else if (ret.S != 0) {
if (ret.F == tmp.F) {
tmp.S += ret.S;
} else {
if (ret.S &gt; tmp.S) {
tmp.F = ret.F;
tmp.S = ret.S - tmp.S;
} else {
tmp.S = tmp.S - ret.S;
}
}
}
}
return tmp;
}
void init() {
cin &gt;&gt; n &gt;&gt; q;
for (int i = 0; i &lt; n; i++) {
cin &gt;&gt; a[i];
T.insert ({a[i], i});
}
}
void solve() {
Node* root = build(0, n - 1);
while (q--) {
int l, r;
cin &gt;&gt; l &gt;&gt; r;
l--, r--;
auto [id, c] = query(root, l, r);
if (c == 0) {
cout &lt;&lt; 0 &lt;&lt; '\n';
continue;
}
int cnt = T.order_of_key(mk(id, r + 1)) - T.order_of_key(mk(id, l)); if (cnt &gt; (r - l + 1) / 2) {
cout &lt;&lt; id &lt;&lt; '\n';
} else {
cout &lt;&lt; 0 &lt;&lt; '\n';
}
}
}
signed main() {
int t = 1;
while (t--) {
init();
solve();
}
} </code></pre> TIOJ 2140. 殿壬愛序列 <p>給一個長度為 \(n\) 的序列，請支援三種操作：</p> <ol> <li>給定 \(i,x\)，將 \(a_i\) 設成 \(x\)</li> <li>給定 \(l,r,k\)，\(\forall l\le i\le r,a_i=\lfloor \frac{a_i}{k} \rfloor\)</li> <li>給定 \(l,r\)，輸出 \(a_l,a_{l+1},\ldots ,a_r\) 的絕對多數，若不存在輸出 \(-1\)</li> </ol> <p>\(n,q\le 10^5\)</p> 思路 <p>參考 : https://abc864197532.github.io/2021/02/07/tioj-2140/</p> <p>區間除法的部分，因為 \(k = 1\) 不會影響陣列，所以可以視為 \(k \geq 2\)。當區間的最大值 \(&gt;0\) 的時候才繼續遞迴下去。這樣一來每個數最多只會被除 \(\log C\) 次。實作上每次將一個點除到 \(0\) 需要 \(O(\log C\times \log n)\)，又每次修改只是單點修改，所以複雜度會是 \(O((n + q)\log C \log n)\approx 1.2\times 10^8\)。</p> <pre><code>// 區間除法代碼
void division(Node* root, int mL, int mR, int val) {
if (root-&gt;r &lt; mL || mR &lt; root-&gt;l) return;
if (root-&gt;l == root-&gt;r) {
root-&gt;id /= val;
root-&gt;mx = root-&gt;id;
return;
}
if (mL &lt;= root-&gt;lc-&gt;r &amp;&amp; root-&gt;lc-&gt;mx) {
division(root-&gt;lc, mL, mR, val);
}
if (root-&gt;rc-&gt;l &lt;= mR &amp;&amp; root-&gt;rc-&gt;mx) {
division(root-&gt;rc, mL, mR, val);
}
root-&gt;pull();
}
</code></pre> <p>單點修改，區間絕對眾數上面都有提到，略。</p> 實作細節 <p>記得要特判 k = 1</p> code <pre><code>#include &lt;bits/stdc++.h&gt;
#include &lt;bits/extc++.h&gt;
#define int long long
#define pii pair&lt;int, int&gt;
#define pb push_back
#define mk make_pair
#define F first
#define S second
#define ALL(x) x.begin(), x.end()
using namespace std;
using namespace __gnu_pbds;
tree&lt;pii,null_type,less&lt;pii&gt;,rb_tree_tag,tree_order_statistics_node_update&gt; T;
const int INF = 2e18;
const int maxn = 3e5 + 5;
const int M = 1e9 + 7;
struct Node{
int l, r;
Node *lc = nullptr;
Node *rc = nullptr;
int id = -1, cnt = 0;
int mx;
Node (int l, int r) : l(l), r(r) {}
void pull () {
if (lc-&gt;cnt == 0) {
id = rc-&gt;id;
cnt = rc-&gt;cnt;
} else if (rc-&gt;cnt == 0) {
id = lc-&gt;id;
cnt = lc-&gt;cnt;
} else {
if (lc-&gt;id == rc-&gt;id) {
id = lc-&gt;id;
cnt = lc-&gt;cnt + rc-&gt;cnt;
} else {
if (lc-&gt;cnt &gt; rc-&gt;cnt) {
id = lc-&gt;id;
cnt = lc-&gt;cnt - rc-&gt;cnt;
} else {
id = rc-&gt;id;
cnt = rc-&gt;cnt - lc-&gt;cnt;
}
}
}
mx = max(lc-&gt;mx, rc-&gt;mx);
}
};
int n, q;
int a[maxn];
Node* build (int l, int r) {
Node* root = new Node(l, r);
if (l == r) {
root-&gt;id = a[l];
root-&gt;cnt = 1;
root-&gt;mx = a[l];
return root;
}
int mid = (l + r) / 2;
root-&gt;lc = build(l, mid);
root-&gt;rc = build(mid + 1, r);
root-&gt;pull();
return root;
}
void update(Node* root, int pos, int val) {
if (root-&gt;l == root-&gt;r) {
T.erase({root-&gt;id, root-&gt;l});
root-&gt;id = val;
root-&gt;cnt = 1;
root-&gt;mx = val;
T.insert({root-&gt;id, root-&gt;l});
return;
}
if (pos &lt;= root-&gt;lc-&gt;r) {
update(root-&gt;lc, pos, val);
} else {
update(root-&gt;rc, pos, val);
}
root-&gt;pull();
}
void division(Node* root, int mL, int mR, int val) {
if (root-&gt;r &lt; mL || mR &lt; root-&gt;l) return;
if (root-&gt;l == root-&gt;r) {
T.erase({root-&gt;id, root-&gt;l});
root-&gt;id /= val;
root-&gt;mx = root-&gt;id;
T.insert({root-&gt;id, root-&gt;l});
return;
}
if (mL &lt;= root-&gt;lc-&gt;r &amp;&amp; root-&gt;lc-&gt;mx) {
division(root-&gt;lc, mL, mR, val);
}
if (root-&gt;rc-&gt;l &lt;= mR &amp;&amp; root-&gt;rc-&gt;mx) {
division(root-&gt;rc, mL, mR, val);
}
root-&gt;pull();
}
pii query(const Node* root, int ql, int qr) {
if (qr &lt; root-&gt;l || root-&gt;r &lt; ql) return {-1, 0};
if (ql &lt;= root-&gt;l &amp;&amp; root-&gt;r &lt;= qr) {
return {root-&gt;id, root-&gt;cnt};
} pii tmp = {-1, 0};
if (ql &lt;= root-&gt;lc-&gt;r) {
pii ret = query(root-&gt;lc, ql, qr);
if (tmp.S == 0) {
tmp = ret;
} else if (ret.S != 0) {
if (ret.F == tmp.F) {
tmp.S += ret.S;
} else {
if (ret.S &gt; tmp.S) {
tmp.F = ret.F;
tmp.S = ret.S - tmp.S;
} else {
tmp.S = tmp.S - ret.S;
}
}
}
}
if (root-&gt;rc-&gt;l &lt;= qr) {
pii ret = query(root-&gt;rc, ql, qr);
if (tmp.S == 0) {
tmp = ret;
} else if (ret.S != 0) {
if (ret.F == tmp.F) {
tmp.S += ret.S;
} else {
if (ret.S &gt; tmp.S) {
tmp.F = ret.F;
tmp.S = ret.S - tmp.S;
} else {
tmp.S = tmp.S - ret.S;
}
}
}
}
return tmp;
}
void init() {
cin &gt;&gt; n &gt;&gt; q;
for (int i = 0; i &lt; n; i++) {
cin &gt;&gt; a[i];
T.insert ({a[i], i});
}
}
void solve() {
Node* root = build(0, n - 1);
int op;
while(q--) {
cin &gt;&gt; op;
if (op == 1) {
int i, x;
cin &gt;&gt; i &gt;&gt; x;
i--;
update(root, i, x);
} else if (op == 2) {
int l, r, k;
cin &gt;&gt; l &gt;&gt; r &gt;&gt; k;
l--, r--;
if (k &gt; 1) division(root, l, r, k);
} else {
int l, r;
cin &gt;&gt; l &gt;&gt; r;
l--, r--;
auto [id, c] = query(root, l, r);
if (c == 0) {
cout &lt;&lt; "-1" &lt;&lt; '\n';
continue;
}
int cnt = T.order_of_key(mk(id, r + 1)) - T.order_of_key(mk(id, l)); if (cnt &gt; (r - l + 1) / 2) {
cout &lt;&lt; id &lt;&lt; '\n';
} else {
cout &lt;&lt; "-1" &lt;&lt; '\n';
}
}
}
}
signed main() {
ios::sync_with_stdio(0);
cin.tie(0);
int t = 1;
//cin &gt;&gt; t;
while (t--) {
init();
solve();
}
}
