const int INF = 2e18;
const int maxn = 3e5 + 5;
const int M = 1e9 + 7;
struct Node {
int key, pri;
Node* lc = nullptr;
Node* rc = nullptr;
int sz = 1;
int cnt = 1;
Node(int key) : key(key), pri(rand()) {
}
void pull() {
sz = cnt;
if (lc) sz += lc-&gt;sz;
if (rc) sz += rc-&gt;sz;
}
};
Node* Merge(Node* a, Node* b) {
if (!a) return b;
if (!b) return a;
if (a-&gt;pri &gt; b-&gt;pri) {
a-&gt;rc = Merge(a-&gt;rc, b);
a-&gt;pull();
return a;
} else {
b-&gt;lc = Merge(a, b-&gt;lc);
b-&gt;pull();
return b;
}
}
// [A, B] : A &lt;= val, B &gt; val
pair&lt;Node*, Node*&gt; Split(Node* root, int val) {
if (!root) return {nullptr, nullptr};
if (root-&gt;key &lt;= val) {
auto [A, B] = Split(root-&gt;rc, val);
root-&gt;rc = A;
root-&gt;pull();
return {root, B};
} else {
auto [A, B] = Split(root-&gt;lc, val);
root-&gt;lc = B;
root-&gt;pull();
return {A, root};
}
}
Node* find_kth(Node* root, int k) {
if (!root) return nullptr;
int cntL;
if (root-&gt;lc) {
cntL = root-&gt;lc-&gt;sz;
} else {
cntL = 0;
}
if (cntL &gt;= k) {  // in left
return find_kth(root-&gt;lc, k);
} else if (cntL + root-&gt;cnt &gt;= k) {
return root;
} else {
return find_kth(root-&gt;rc, k - cntL - root-&gt;cnt);
}
}
