struct Node {
int pri;
Node* lc;
Node* rc;
// lazy tag
int rev;
int add;
// original data
int sz;
// extra data
int val;
int mn;
Node (int val) : val(val), mn(val) , pri(rand()), lc(nullptr), rc(nullptr), sz(1), rev(0), add(0) {}
void push() {
if (rev) {
swap(lc, rc);
if (lc) lc-&gt;rev ^= 1;
if (rc) rc-&gt;rev ^= 1;
rev = 0;
}
if (add) {
if (lc) {
lc-&gt;add += add;
lc-&gt;val += add;
lc-&gt;mn += add;
}
if (rc) {
rc-&gt;add += add;
rc-&gt;val += add;
rc-&gt;mn += add;
}
add = 0;
}
}
void pull() {
mn = val;
sz = 1;
if (lc) {
mn = min(lc-&gt;mn, mn);
sz += lc-&gt;sz;
}
if (rc) {
mn = min(rc-&gt;mn, mn);
sz += rc-&gt;sz;
}
}
};
struct DS {
void init(const vector&lt;int&gt; &amp;a) {
