}
void reverse(int l, int r) {
pair&lt;Node*, Node*&gt; p1 = SplitBySize(root, r);
pair&lt;Node*, Node*&gt; p2 = SplitBySize(p1.F, l - 1);
if (p2.S == nullptr) {
root = Merge(p2.F, p1.S);
return;
}
p2.S-&gt;rev ^= 1;
root = Merge(Merge(p2.F, p2.S), p1.S);
}
int min(int l, int r) {
