if (!b) return a;
if (a-&gt;pri &gt; b-&gt;pri) {
a = new Node(*a);
a-&gt;rc = Merge(a-&gt;rc, b);
a-&gt;pull();
return a;
} else {
b = new Node(*b);
b-&gt;lc = Merge(a, b-&gt;lc);
b-&gt;pull();
return b;
}
}
// [A, B] : A &lt;= val, B &gt; val
pair&lt;Node*, Node*&gt; Split(Node* root, int val) {
if (!root) return {nullptr, nullptr};
root = new Node(*root);
if (root-&gt;key &lt;= val) {
auto [A, B] = Split(root-&gt;rc, val);
root-&gt;rc = A;
root-&gt;pull();
return {root, B};
} else {
auto [A, B] = Split(root-&gt;lc, val);
root-&gt;lc = B;
root-&gt;pull();
return {A, root};
}
}
int find_kth(Node* root, int k) {
if (!root) return INF;
int cntL;
if (root-&gt;lc) {
cntL = root-&gt;lc-&gt;sz;
} else {
cntL = 0;
}
if (cntL &gt;= k) {  // in left
return find_kth(root-&gt;lc, k);
} else if (cntL + root-&gt;cnt &gt;= k) {
return root-&gt;key;
} else {
return find_kth(root-&gt;rc, k - cntL - root-&gt;cnt);
}
}
struct DS {
vector&lt;Node*&gt; roots = {nullptr};
void insert(int pre, int x) {
auto [A, B] = Split(roots[pre], x - 1);
auto [C, D] = Split(B, x);
if (C == nullptr) {
Node* tmp = new Node(x);
roots.pb(Merge(A, Merge(tmp, D)));
return;
}
C-&gt;cnt++;
C-&gt;sz++;
roots.pb(Merge(A, Merge(C, D)));
}
void erase(int pre, int x) {
auto [A, B] = Split(roots[pre], x - 1);
auto [C, D] = Split(B, x);
if (C == nullptr) {
roots.pb(Merge(A, D));
return;
}
C-&gt;cnt--;
C-&gt;sz--;
if (C-&gt;cnt == 0) {
delete C;
C = nullptr;
}
roots.pb(Merge(A, Merge(C, D)));
}
int find_rank(int pre, int x) {
auto [A, B] = Split(roots[pre], x - 1);
if (A == nullptr) {
roots.pb(Merge(A, B));
return 1;
}
int ans = A-&gt;sz + 1;
roots.pb(Merge(A, B));
return ans;
}
int find_by_order(int pre, int k) {
int x = find_kth(roots[pre], k);
roots.pb(new Node(*roots[pre]));
return x;
}
int find_largest_less(int pre, int x) {
auto [A, B] = Split(roots[pre], x - 1);
if (A == nullptr) {
roots.pb(Merge(A, B));
return -1;
}
int tmp = find_kth(A, A-&gt;sz);
roots.pb(Merge(A, B));
if (tmp == INF) tmp = -tmp;
return tmp;
}
int find_smallest_greater(int pre, int x) {
auto [A, B] = Split(roots[pre], x);
if (B == nullptr) {
roots.pb(Merge(A, B));
return -1;
}
int tmp = find_kth(B, 1);
roots.pb(Merge(A, B));
return tmp;
}
};
signed main() {
ios::sync_with_stdio(0);
cin.tie(0);
cout.tie(0);
int q;
cin &gt;&gt; q;
DS rank_tree;
int v, op, x;
while (q--) {
cin &gt;&gt; v &gt;&gt; op &gt;&gt; x;
if (op == 1) {
rank_tree.insert(v, x);
} else if (op == 2) {
rank_tree.erase(v, x);
} else if (op == 3) {
cout &lt;&lt; rank_tree.find_rank(v, x) &lt;&lt; '\n';
} else if (op == 4) {
cout &lt;&lt; rank_tree.find_by_order(v, x) &lt;&lt; '\n';
} else if (op == 5) {
cout &lt;&lt; rank_tree.find_largest_less(v, x) &lt;&lt; '\n';
} else if (op == 6) {
cout &lt;&lt; rank_tree.find_smallest_greater(v, x) &lt;&lt; '\n';
}
}
}
</code></pre> 持久化 Treap 洛谷 P5055 【模板】可持久化文艺平衡树 <p>來維護一個序列，其中需要提供以下操作 :</p> <ol> <li>在第 \(i\) 個數後插入數字 \(x\) </li> <li>刪除第 \(i\) 個數</li> <li>reverse 區間 \(a_l,\ldots ,a_r\)</li> <li>輸出 \(a_l+\ldots +a_r\)</li> </ol> <p>每一次操作都是基於某一個歷史版本，同時生成一個新的版本</p> <p>\(1 \le n \le 2 \times {10}^5\)，\(|x_i| &lt; {10}^6\)</p> code <pre><code>#include &lt;bits/stdc++.h&gt;
#define int long long
#define pii pair&lt;int, int&gt;
#define pb push_back
#define mk make_pair
#define F first
#define S second
#define ALL(x) x.begin(), x.end()
using namespace std;
const int INF = 2e18;
const int maxn = 3e5 + 5;
const int M = 1e9 + 7;
struct Node {
int pri;
Node *lc = nullptr;
Node *rc = nullptr;
int sz = 1;
int sum;
int val;
int rev = 0;
Node (int val) : val(val), sum(val), pri(rand()) {}
void push() {
if (rev) {
swap(lc, rc);
if (lc) lc = new Node(*lc);
if (rc) rc = new Node(*rc);
if (lc) lc-&gt;rev ^= 1;
if (rc) rc-&gt;rev ^= 1;
rev = 0;
}
}
void pull() {
sz = 1;
sum = val;
if (lc) {
sz += lc-&gt;sz;
sum += lc-&gt;sum;
}
if (rc) {
sz += rc-&gt;sz;
sum += rc-&gt;sum;
}
}
};
Node* Merge(Node* a, Node *b) {
if (!a) return b;
if (!b) return a;
if (a-&gt;pri &gt; b-&gt;pri) {
a = new Node(*a);
a-&gt;push();
a-&gt;rc = Merge(a-&gt;rc, b);
a-&gt;pull();
return a;
} else {
b = new Node(*b);
b-&gt;push();
b-&gt;lc = Merge(a, b-&gt;lc);
b-&gt;pull();
return b;
}
}
pair&lt;Node*, Node*&gt; SplitBySize(Node* root, int k) {
if (!root) return {nullptr, nullptr};
root = new Node(*root);
root-&gt;push();
int cntL = 0;
if (root-&gt;lc) cntL = root-&gt;lc-&gt;sz + 1;
else cntL = 1;
if (cntL &lt;= k) {
auto [A, B] = SplitBySize(root-&gt;rc, k - cntL);
root-&gt;rc = A;
root-&gt;pull();
return {root, B};
} else {
auto [A, B] = SplitBySize(root-&gt;lc, k);
root-&gt;lc = B;
root-&gt;pull();
return {A, root};
}
}
struct DS {
vector&lt;Node*&gt; roots = {nullptr};
void insert(int pre, int k, int x) {
//cout &lt;&lt; "insert" &lt;&lt; ",pre:" &lt;&lt; pre &lt;&lt; ",k:" &lt;&lt; k &lt;&lt; ",x:" &lt;&lt; x &lt;&lt; '\n';
auto [A, B] = SplitBySize(roots[pre], k);
Node* tmp = new Node(x);
roots.pb(Merge(A, Merge(tmp, B)));
}
void erase(int pre, int k) {
//cout &lt;&lt; "erase" &lt;&lt; ",pre:" &lt;&lt; pre &lt;&lt; ",k:" &lt;&lt; k &lt;&lt; '\n';
auto [A, B] = SplitBySize(roots[pre], k - 1);
auto [C, D] = SplitBySize(B, 1);
roots.pb(Merge(A, D));
}
void reverse(int pre, int l, int r) {
//cout &lt;&lt; "reverse" &lt;&lt; ",pre:" &lt;&lt; pre &lt;&lt; ",l:" &lt;&lt; l &lt;&lt; ",r:" &lt;&lt; r &lt;&lt; '\n';
auto [A, B] = SplitBySize(roots[pre], r);
auto [C, D] = SplitBySize(A, l - 1);
if (D == nullptr) {
roots.pb(Merge(C, B));
return;
}
D-&gt;rev ^= 1;
roots.pb(Merge(Merge(C, D), B));
}
int sum(int pre, int l, int r) {
//cout &lt;&lt; "sum" &lt;&lt; ",pre:" &lt;&lt; pre &lt;&lt; ",l:" &lt;&lt; l &lt;&lt; ",r:" &lt;&lt; r &lt;&lt; '\n';
auto [A, B] = SplitBySize(roots[pre], r);
auto [C, D] = SplitBySize(A, l - 1);
if (D == nullptr) {
roots.pb(Merge(C, B));
return -1;
}
int ans = D-&gt;sum;
roots.pb(Merge(Merge(C, D), B));
return ans;
}
int show(int pre, int k) { // debug
auto [A, B] = SplitBySize(roots[pre], k - 1);
auto [C, D] = SplitBySize(B, 1);
if (C == nullptr) {
roots[pre] = Merge(A, D);
return -1;
}
int ans = C-&gt;val;
roots[pre] = Merge(A, Merge(C, D));
return ans;
}
void print(int pre) { // debug
cout &lt;&lt; "print:\n---------\n"; if (roots.size() &lt;= pre || roots[pre] == nullptr) {
cout &lt;&lt; "failed print\n";
return;
}
int n = roots[pre]-&gt;sz;
for (int i = 1; i &lt;= n; i++) {
cout &lt;&lt; show(pre, i) &lt;&lt; '\n';
}
cout &lt;&lt; "-------\n";
}
};
signed main() {
int q;
cin &gt;&gt; q;
DS ds;
int last = 0;
while (q--) {
int v, op;
cin &gt;&gt; v &gt;&gt; op;
if (op == 1) {
int k, x;
cin &gt;&gt; k &gt;&gt; x;
k ^= last;
x ^= last;
ds.insert(v, k, x);
} else if (op == 2) {
int k;
cin &gt;&gt; k;
k ^= last;
ds.erase(v, k);
} else if (op == 3) {
int l, r;
cin &gt;&gt; l &gt;&gt; r;
l ^= last;
r ^= last;
ds.reverse(v, l, r);
} else if (op == 4) {
int l, r;
cin &gt;&gt; l &gt;&gt; r;
l ^= last;
r ^= last;
last = ds.sum(v, l, r);
cout &lt;&lt; last &lt;&lt; '\n';
}
}
} </code></pre>

