模板 CF EDU DSU A. DSU with rollback <p>有 \(n\) 個點與 \(m\) 個以下操作 : </p> <ul> <li> <p>\(\text{union}(u,v):\) 將 \(u,v\) 所在的連通塊合併成同一個連通塊</p> </li> <li> <p>\(\text{persist}:\) 新增一個 checkpoint</p> </li> <li> <p>\(\text{rollback:}\) 回到上一個還沒被 rollback 的 checkpoint</p> </li> </ul> <p>\(n,m\le 2\times 10^5\)</p> 模板 <pre><code>struct Graph {
Graph (int n) : n(n) {
sz = vector&lt;int&gt;(n, 1);
par = vector&lt;int&gt;(n);
cnt = n;
for (int i = 0; i &lt; n; i++) {
par[i] = i;
}
}
void add_edge (int u, int v) {
int x = find (u), y = find (v);
if (x == y) {
stk.push ({x, x});
return;
}
if (sz[x] &lt; sz[y]) swap (x, y);
sz[x] += sz[y]; par[y] = x;
cnt--;
stk.push ({x, y});
}
void undo () {
auto [x, y] = stk.top ();
stk.pop ();
if (x == y) return;
sz[x] -= sz[y]; par[y] = y;
cnt++;
}
int size () {
return cnt;
}
private :
int n, cnt;
vector&lt;int&gt; sz;
vector&lt;int&gt; par;
stack&lt;pii&gt; stk;
int find (int x) {
if (par[x] == x) return x;
else return find (par[x]);
}
};
</code></pre>

