int u = idx(i, j);
int v = idx(i - 1, j);
int w = abs(A[i][j] - A[i - 1][j]);
g[u].push_back({w, v});
g[v].push_back({w, u});
edges.push_back({w, u, v});
}
if (j &gt; 0) {
int u = idx(i, j);
int v = idx(i, j - 1);
int w = abs(A[i][j] - A[i][j - 1]);
g[u].push_back({w, v});
g[v].push_back({w, u});
edges.push_back({w, u, v});
}
}
}
}
const int M = 1024;
vector&lt;array&lt;int, 3&gt;&gt; bucket[M];
void sortEdges() {
// sort(edges.begin(), edges.end());
// Radix sort (1024 進位)
{
// 先考慮 1024 以下的位元
for (auto e : edges) {
int w = e[0];
bucket[w &amp; 1023].push_back(e);
}
// 讓 edges 裡面的 edge 以 1024 以下的位元排序
int pos = 0;
for (int i = 0; i &lt; M; i++) {
for (auto e : bucket[i]) {
edges[pos++] = e;
}
}
for (int i = 0; i &lt; M; i++) bucket[i].clear();
}
{
// 在 edge 以 1024 以下的位元排序後的前提下
// 再考慮 1024 以上的位元
for (auto e : edges) {
int w = e[0];
bucket[w &gt;&gt; 10].push_back(e);
}
int pos = 0;
for (int i = 0; i &lt; M; i++) {
for (auto e : bucket[i]) {
edges[pos++] = e;
}
}
}
}
