for (int i = 0; i &lt; n * n; i++) par[i] = i;
int src = idx(0, 0);
int dst = idx(n - 1, n - 1);
for (auto [w, u, v] : edges) {
if (find(u) != find(v)) {
par[find(u)] = find(v);
}
