for (int i = 1; i &lt;= m; i++) cin &gt;&gt; arr[i].a &gt;&gt; arr[i].c;
sort(arr + 1, arr + m + 1);
long long ans = 0;
int x_i = n;
for (int i = 1; i &lt;= m; i++) {
int last = x_i;
