#define int long long
#define pii pair&lt;int, int&gt;
#define pb push_back
#define mk make_pair
#define F first
#define S second
#define ALL(x) x.begin(), x.end()
using namespace std;
using PQ = priority_queue&lt;int, vector&lt;int&gt;, greater&lt;int&gt;&gt;;
const int INF = 2e18;
const int maxn = 300 + 5;
const int M = 1e9 + 7;
int n, m, K;
int dis[maxn][maxn];
int cnt[maxn][maxn];
pii dp[maxn][maxn];
void floyd () {
for (int k = 1; k &lt;= n; k++) {
for (int i = 1; i &lt;= n; i++) {
for (int j = 1; j &lt;= n; j++) {
if (dis[i][j] == dis[i][k] + dis[k][j]) {
cnt[i][j] += cnt[i][k] * cnt[k][j];
}
else if (dis[i][j] &gt; dis[i][k] + dis[k][j]) {
dis[i][j] = dis[i][k] + dis[k][j];
cnt[i][j] = cnt[i][k] * cnt[k][j];
}
}
}
}
}
void init () {
cin &gt;&gt; n &gt;&gt; m &gt;&gt; K;
int u, v, w;
for (int i = 1; i &lt;= n; i++) {
for (int j = 1; j &lt;= n; j++) {
dis[i][j] = INF;
}
dis[i][i] = 0;
}
for (int i = 1; i &lt;= m; i++) {
cin &gt;&gt; u &gt;&gt; v &gt;&gt; w;
dis[u][v] = dis[v][u] = min (w, dis[u][v]);
cnt[u][v] = cnt[v][u] = 1;
}
}
void solve () {
floyd ();
vector&lt;pii&gt; ord;
for (int i = 1; i &lt;= n; i++) {
ord.pb ({dis[1][i], i});
cnt[i][i] = 1;
}
sort (ALL(ord)); // sort by distance
// dp init
for (int i = 0; i &lt; n; i++) {
int u = ord[i].S;
if (dis[1][u] + dis[u][n] != dis[1][n]) continue;
dp[u][1] = {cnt[1][u], 1};
}
// (v -&gt; u) 一定是 v 先被走到再來才是 u，距離是一種可以判斷先後的好方法
for (int i = 0; i &lt; ord.size (); i++) {
int u = ord[i].S;
if (dis[1][u] + dis[u][n] != dis[1][n]) continue; // check u
for (int j = 0; j &lt; i; j++) {
int v = ord[j].S;
if (dis[1][v] + dis[v][u] + dis[u][n] != dis[1][n]) continue; // check v
for (int k = 2; k &lt;= K; k++) {
pii tmp;
tmp.F = dp[v][k - 1].F * cnt[v][u];
tmp.S = dp[v][k - 1].S;
if (tmp.F &gt; dp[u][k].F)
dp[u][k] = tmp;
else if (tmp.F == dp[u][k].F) {
dp[u][k].S += tmp.S;
if (dp[u][k].S &gt;= M)
dp[u][k].S -= M;
}
}
}
} pii res = {0, 0};
// 以 u 結尾，還缺少到 u -&gt; n 這段，補起來
// 可是 n 結尾上面有算過了阿? 不一定會以 n 結尾 但最短路可延續至 n
for (int i = 1; i &lt;= n; i++) {
if (dis[1][i] + dis[i][n] != dis[1][n])
continue;
dp[i][K].F *= cnt[i][n];
if (dp[i][K].F &gt; res.F)
res = dp[i][K];
else if (dp[i][K].F == res.F) {
res.S += dp[i][K].S;
if (res.S &gt;= M)
res.S -= M;
}
}
cout &lt;&lt; res.F &lt;&lt; " " &lt;&lt; res.S &lt;&lt; "\n";
