} </code></pre> CSES - Visiting Cities <p>給 \(n\) 點 \(m\) 邊正權有向圖，從 \(1\to n\) 判斷每個邊</p> <ul> <li>是否在每個最短路徑上</li> </ul> <p>\(n\le 10^5, m\le 2\times 10^5\)</p> 思路 <p>建立 shotest path DAG，進行 DAG DP</p> <p>\(dp(1 \to u):\) \(1\to u\) 是最短路的路徑方法數</p> <p>\(dp(u \to n):\) \(u\to n\) 是最短路的路徑方法數</p> <p>判斷 \(dp(1 \to u)\times dp(v\to n)==dp(s\to t)\)</p> code <pre><code>#include &lt;bits/stdc++.h&gt;
#define int long long
#define pii pair&lt;int, int&gt;
#define pb push_back
#define mk make_pair
#define F first
#define S second
#define ALL(x) x.begin(), x.end()
using namespace std;
using PQ = priority_queue&lt;int, vector&lt;int&gt;, greater&lt;int&gt;&gt;;
const int INF = 2e18;
const int maxn = 3e5 + 5;
const int M = 2147483647;
int n, m;
vector&lt;pii&gt; G[maxn];
vector&lt;pii&gt; R[maxn];
vector&lt;int&gt; D[maxn];
vector&lt;int&gt; P[maxn];
int in[maxn], rv[maxn];
vector&lt;int&gt; dijkstra (int source, vector&lt;pii&gt; *G) {
vector&lt;int&gt; dis(n + 1, INF);
priority_queue &lt;pii, vector&lt;pii&gt;, greater&lt;pii&gt;&gt; pq;
pq.push ({0, source});
while (pq.size()) {
auto [x, u] = pq.top();
pq.pop();
if (dis[u] != INF) continue;
dis[u] = x;
for (auto [v, w] : G[u]) {
pq.push ({x + w, v});
}
}
return dis;
}
void build (vector&lt;int&gt; &amp;dis) {
for (int i = 1; i &lt;= n; i++) {
for (auto [v, w] : G[i]) {
if (dis[v] == dis[i] + w) {
D[i].push_back(v);
P[v].pb(i);
in[v]++;
rv[i]++;
}
}
}
}
vector&lt;int&gt; topo (int source, int *in, vector&lt;int&gt; *D) {
queue&lt;int&gt; q;
vector&lt;int&gt; inn(n + 1);
vector&lt;int&gt; dp(n + 1);
dp[source] = 1;
for (int i = 1; i &lt;= n; i++) {
if (in[i] == 0) q.push (i);
inn[i] = in[i];
}
while (q.size()) {
int u = q.front();
q.pop();
for (auto v : D[u]) {
dp[v] = (dp[v] + dp[u]) % M;
inn[v]--;
if (inn[v] == 0) q.push (v);
}
}
return dp;
}
void init () {
cin &gt;&gt; n &gt;&gt; m;
int u, v, w;
for (int i = 0; i &lt; m; i++) {
cin &gt;&gt; u &gt;&gt; v &gt;&gt; w;
G[u].pb({v, w});
R[v].pb({u, w});
}
}
void solve() {
vector&lt;int&gt; dis = dijkstra (1, G);
vector&lt;int&gt; rev = dijkstra (n, R);
build (dis);
vector&lt;int&gt; dp1 = topo (1, in, D);
vector&lt;int&gt; dp2 = topo (n, rv, P);
int tot = dp1[n];
vector&lt;int&gt; res;
for (int i = 1; i &lt;= n; i++) {
int cur = (dp1[i] * dp2[i]) % M;
if (cur == tot) {
res.pb(i);
}
}
cout &lt;&lt; res.size() &lt;&lt; "\n";
for (int i = 0; i &lt; res.size(); i++) cout &lt;&lt; res[i] &lt;&lt; " ";
} signed main() {
// ios::sync_with_stdio(0);
// cin.tie(0);
int t = 1;
//cin &gt;&gt; t;
while (t--) {
init();
solve();
