int check (int x) {
for (int l = 1, r = cnt; l &lt; r; l++, r--) {
if (l == x) l++;
if (r == x) r--;
if (l &lt; r &amp;&amp; g[l] + g[r] &gt; lim) return false;
}
return true;
}
int dfs (int u, int par) {
for (auto v : G[u]) {
if (v == par) continue;
if (dfs (v, u) == 0) return 0;
}
cnt = 0;
for (auto v : G[u]) {
if (v == par) continue;
g[++cnt] = f[v];
}
sort (g + 1, g + cnt + 1);
if (u == 1) {
if (cnt &amp; 1) {
cnt--;
return check (0);
}
else {
return check (0);
}
}
if (cnt % 2 == 0) {
if (check (0)) {
f[u] = 1;
return 1;
}
cnt--;
}
int l = 1, r = cnt + 1;
while (l &lt; r) {
int mid = (l + r) / 2;
if (check (mid)) r = mid;
else l = mid + 1;
}
if (l == cnt + 1) return 0;
f[u] = g[l] + 1;
return f[u] &lt;= lim;
}
void init () {
cin &gt;&gt; n;
