G[u].pb (v);
G[v].pb (u);
deg[u]++, deg[v]++;
}
int sum = 0;
sum += (deg[1] + 1) / 2;
for (int i = 2; i &lt;= n; i++) sum += (deg[i] - 1) / 2;
cout &lt;&lt; sum &lt;&lt; " ";
}
void solve () {
int l = 1, r = n - 1;
while (l &lt; r) {
int mid = (l + r) / 2;
lim = mid;
