for (int i = 1; i &lt;= n; i++) {
if (deg[i] &lt;= x) q.push (i);
}
while (q.size ()) {
int u = q.top(); q.pop();
vis[u] = true;
for (auto v : G[u]) {
if (vis[v]) continue;
deg[v]--;
if (deg[v] &lt;= x) q.push (v);
}
}
for (int i = 1; i &lt;= n; i++) {
if (vis[i] == false) return false;
}
return true;
}
</code></pre> <p>複雜度 : \(O((n+m)\log n)\)</p> <p>法 2 : greedy 想法</p> <p>依序枚舉 1 ~ n，放在 <code>deg[i]</code> 最小的，用 pq 維護當前 deg 最小的</p> <p>將某個點 u 周圍的 <code>deg[v]--</code> 的話要怎麼做 ?</p> <p>想想看 dijkstra 是怎麼做到這件事的</p> <p>就像 dijkstra 那樣直接 push 一個新的進去 pq 即可</p> <p>pq 再拿某個點出來時記得檢查是否過期</p> <p>複雜度 : \(O((n+m)\log n)\)</p> <p>法 3 : 優化法 2</p> <p>此方法實測是不能通過的，只是一個想法</p> <p>開 \(n\) 個 vector，<code>v[i]</code> 放所有 degree = i 的點</p> <p>每次更新 degree 就不管 <code>v[deg[i]]</code>，直接 push 一個到 <code>v[deg[i]--]</code></p> <p>複雜度 : \(O(n+m)\)</p> 2017 全國賽 p5 <p>給你一張 \(n\) 點 \(m\) 邊無向圖，選一些點 ( 我們把這個點集合叫做 \(S\) )，\(S\) 內的點必須連通</p> <p>問 \(F(S)\) 最大多少</p> \[F(S) = \lvert S \rvert  \min\limits_{1\leq i \leq \lvert S \rvert} \{ D_i \}\] <p>其中 \(D_i\) 表示 \(i\) 的鄰居裡面，有多少人在 \(S\) 內</p> <p>\(n\le 5000\)</p> 思路 <p>我們考慮從枚舉 \(D_i\) 下手 </p> <ul> <li> <p>\(D_i=1\) 這時其實就是整張圖</p> </li> <li> <p>\(D_i=2\) 因為 degree 是 \(1\) 的點不能選，所以刪除 \(\deg \le 1\) 的點，並將周圍的點的 degree -1</p> </li> <li> <p>\(D_i=3\) 刪除 \(\deg \le 2\) 的點，並將周圍的點的 degree -1</p> </li> <li> <p>\(D_i=4\) 刪除 \(\deg \le 3\) 的點，並將周圍的點的 degree -1</p> </li> <li> <p>...</p> </li> </ul> <p>可以觀察到當 \(D_i=k\) 的時候需要將 \(\deg \le k-1\) 的點刪掉</p> <p>此時 \(F(S)=\) 剩下的點的數量 \(\times (k-1)\)</p> <p>實作方面沒辦法真的去刪邊，考慮時光倒流技巧，用加邊來看</p> <p>只是你並不能知道要依序加哪些點進去</p> <p>所以我們先預處理好 \(D_i=k+1 \to D_i=k\) 的時候需要加入的點即可</p> <p>預處理就像 topo 排序那樣每輪找 \(\deg = k\) 的點，將他們存在 vector <code>v[k]</code> 裡面</p> code <pre><code>#include &lt;bits/stdc++.h&gt;
#define int long long
#define pii pair&lt;int, int&gt;
#define pb push_back
#define mk make_pair
#define F first
#define S second
#define ALL(x) x.begin(), x.end()
using namespace std;
using PQ = priority_queue&lt;int, vector&lt;int&gt;, greater&lt;int&gt;&gt;;
const int INF = 2e18;
const int maxn = 5e3 + 5;
const int M = 1e9 + 7;
int n, m;
vector&lt;int&gt; G[maxn];
vector&lt;int&gt; V[maxn];
int in[maxn], vis[maxn], par[maxn], sz[maxn];
void dsu_init () {
for (int i = 1; i &lt;= n; i++) {
par[i] = i;
sz[i] = 1;
}
}
int find (int x) {
if (par[x] == x) return x;
else return par[x] = find (par[x]);
}
void merge (int a, int b) {
int x = find (a), y = find (b);
if (x == y) return;
par[x] = y;
sz[y] += sz[x];
sz[x] = 0;
}
void init () {
cin &gt;&gt; n &gt;&gt; m;
int u, v;
for (int i = 0; i &lt; m; i++) {
cin &gt;&gt; u &gt;&gt; v;
G[u].pb (v);
G[v].pb (u);
in[u]++, in[v]++;
}
}
void topo () {
for (int i = 1; i &lt;= n; i++) {
// 刪除 deg[u] &lt;= i 的點
queue&lt;int&gt; q;
for (int j = 1; j &lt;= n; j++) {
if (!vis[j] &amp;&amp; in[j] == i) {
q.push (j);
vis[j] = 1;
}
}
while (q.size ()) {
int u = q.front ();
q.pop ();
V[i].pb (u);
for (auto v : G[u]) {
in[v]--;
if (vis[v]) continue;
if (in[v] &lt;= i) {
q.push (v);
vis[v] = 1;
}
}
}
}
}
void solve () {
topo ();
dsu_init ();
memset (vis, 0, sizeof vis);
int ans = 0;
for (int i = n; i &gt;= 1; i--) {
for (auto u : V[i]) {
vis[u] = 1; for (auto v : G[u]) {
if (!vis[v]) continue;
merge (u, v);
}
}
for (int u = 1; u &lt;= n; u++) {
if (par[u] == u &amp;&amp; vis[u]) {
ans = max (ans, sz[u] * i);
} }
}
cout &lt;&lt; ans &lt;&lt; "\n";
} signed main() {
// ios::sync_with_stdio(0);
// cin.tie(0);
int t = 1;
//cin &gt;&gt; t;
while (t--) {
init();
solve();
}
} </code></pre>

