const int INF = 2e18;
const int maxn = 3e5 + 5;
const int M = 1e9 + 7;
struct node {
node *ch[2];
vector&lt;int&gt; con (int x) {
vector&lt;int&gt; res;
for (int i = 0; i &lt;= 30; i++) {
if (x &amp; (1 &lt;&lt; i)) res.pb (1);
else res.pb (0);
}
return res;
}
void add (int x, node *rt) {
vector&lt;int&gt; res = con (x);
int n = res.size ();
for (int i = n - 1; i &gt;= 0; i--) {
if (rt -&gt; ch[res[i]] == nullptr) rt -&gt; ch[res[i]] = new node ();
rt = rt -&gt; ch[res[i]];
}
}
int find (int x, node *rt) {
vector&lt;int&gt; res = con (x);
int n = res.size();
int ret = 0;
for (int i = n - 1; i &gt;= 0; i--) {
if (rt -&gt; ch[res[i] ^ 1] == nullptr) rt = rt -&gt; ch[res[i]], ret += (res[i] &lt;&lt; i);
else rt = rt -&gt; ch[res[i] ^ 1], ret += ((res[i] ^ 1) &lt;&lt; i);
}
return ret;
}
};
int n;
int a[maxn], pre[maxn];
void init () {
cin &gt;&gt; n;
for (int i = 1; i &lt;= n; i++) cin &gt;&gt; a[i];
}
void solve () {
node *rt = new node ();
int res = 0;
rt -&gt; add (0, rt);
for(int i = 1; i &lt;= n; i++) {
pre[i] = pre[i - 1] ^ a[i];
int ret = rt -&gt; find (pre[i], rt) ^ pre[i];
res = max (res, ret);
rt -&gt; add (pre[i], rt);
}
cout &lt;&lt; res &lt;&lt; "\n";
} signed main() {
