LeetCode 169. Majority Element <p>給一個長度為 \(n\) 的陣列，輸出出現超過 \(\lfloor n/2\rfloor\) 次的數字</p> <p>\(n\le 5\times 10^4\)</p> code <pre><code>class Solution {
public:
int majorityElement(vector&lt;int&gt;&amp; nums) {
int v = -1, c = 0;
for(int x : nums) {
if (v == -1 &amp;&amp; c == 0) {
v = x;
c = 1;
continue;
}
if (v != x) {
c--;
if (c == 0) v = -1;
} else {
c++;
}
}
c = 0;
for(int x : nums) {
if (x == v) c++;
}
int n = nums.size();
if (c &gt; (n / 2)) return v;
else return -1;
}
};
</code></pre> <p>\(x,y\) 打架，分兩種 case :</p> <ul> <li> <p>\(x,y\) 不同 \(\Rightarrow x,y\) 各減少一個</p> </li> <li> <p>otherwise \(\Rightarrow\) 都保留</p> </li> </ul> 可否再線段樹上實現 ? <p>參考此處</p>

LeetCode 229. Majority Element II <p>給一個長度為 \(n\) 的陣列，輸出所有出現超過 \(\lfloor n/3\rfloor\) 次的數字</p> <p>\(n\le 5\times 10^4\)</p> 思路 <p>\(x,y,z\) 打架，分兩種 case :</p> <ul> <li> <p>\(x,y,z\) 都不同 \(\Rightarrow x,y,z\) 各減少一個</p> </li> <li> <p>otherwise \(\Rightarrow\) 都保留</p> </li> </ul> 另解 <p>nth_element 找 rank n/3, 2n/3, 3n/3，然後檢查這些位置的數字出現次數是否 &gt;= [n / 3]</p> <p>因為如果一個數字出現超過 n/3 的話那一定至少碰到 n/3, 2n/3, 3n/3 其中一個</p> <pre><code>------O------O------O
</code></pre> code <pre><code>class Solution {
public:
const int INF = 1e9 + 7;
vector&lt;int&gt; majorityElement(vector&lt;int&gt;&amp; nums) {
int v1 = -INF, c1 = 0;
int v2 = -INF, c2 = 0;
for (int x : nums) {
if (c1 &gt; 0 &amp;&amp; x == v1) {
c1++;
continue;
}
if (c2 &gt; 0 &amp;&amp; x == v2) {
c2++;
continue;
}
if (c1 == 0) {
v1 = x;
c1 = 1;
} else if (c2 == 0) {
v2 = x;
c2 = 1;
} else {
c1--;
if (c1==0) v1 = -INF;
c2--;
if (c2==0) v2 = -INF;
}
}
c1 = 0, c2 = 0;
for (int x : nums) {
if (x == v1) c1++;
if (x == v2) c2++;
}
vector&lt;int&gt; ans;
int n = nums.size();
if (c1 &gt; n/3) ans.push_back(v1);
if (c2 &gt; n/3) ans.push_back(v2);
return ans;
}
};
</code></pre> 正確性證明 <p>如果有一個東西出現超過 \(\lfloor n/3\rfloor\)，那他不可能全部都被丟掉，因為當且僅當 \(x,y,z\) 只有在都不一樣的時候才會被丟掉</p>

洛谷 P3810 三维偏序 <p>給 \(n\) 個三維空間的點 \((x,y,z)\)，問對於第 \(i\) 個點，有幾個 \(j\) 滿足 \(x_j\ge x_i,y_j\ge y_i,z_j\ge z_i\)</p> code <pre><code>#include &lt;bits/stdc++.h&gt;
#define int long long
#define pii pair&lt;int, int&gt;
#define pb push_back
#define mk make_pair
#define lowbit(x) (x &amp; (-x))
#define F first
#define S second
#define ALL(x) x.begin(), x.end()
using namespace std;
using PQ = priority_queue&lt;int, vector&lt;int&gt;, greater&lt;int&gt;&gt;;
const int INF = 2e18;
const int maxn = 3e5 + 5;
const int M = 1e9 + 7;
int n, C;
int ans[maxn];
struct triple {
int a, b, c, cnt, res;
bool operator== (triple &amp;other) {
if (a == other.a &amp;&amp; b == other.b &amp;&amp; c == other.c)
return true;
return false;
}
} a[maxn];
int cmpA (triple A, triple B) {
if (A.a != B.a) return A.a &lt; B.a;
if (A.b != B.b) return A.b &lt; B.b;
return A.c &lt; B.c;
}
int cmpB (triple A, triple B) {
if (A.b != B.b) return A.b &lt; B.b;
return A.c &lt; B.c;
}
struct BIT {
int n;
vector&lt;int&gt; bit;
void init (int _n) {
n = _n;
bit.resize (n + 1);
}
void add (int x, int d) {
while (x &lt;= n) {
bit[x] += d;
x += lowbit (x);
}
}
int query (int x) {
int ret = 0;
while (x &gt; 0) {
ret += bit[x];
x -= lowbit (x);
}
return ret;
}
} bit;
void CDQ (int l, int r) {
if (l == r) return;
int mid = (l + r) / 2;
CDQ (l, mid), CDQ (mid + 1, r);
sort (a + l, a + mid + 1, cmpB);
sort (a + mid + 1, a + r + 1, cmpB);
int i = l, j = mid + 1;
while (j &lt;= r) {
while (i &lt;= mid &amp;&amp; a[i].b &lt;= a[j].b) {
bit.add (a[i].c, a[i].cnt);
i++;
}
a[j].res += bit.query (a[j].c);
j++;
}   // undo
for (int k = l; k &lt; i; k++) {
bit.add (a[k].c, -a[k].cnt);
}
return;
}
void solve () {
cin &gt;&gt; n &gt;&gt; C;
vector&lt;triple&gt; tmp (n);
for (int i = 0; i &lt; n; i++) {
cin &gt;&gt; tmp[i].a &gt;&gt; tmp[i].b &gt;&gt; tmp[i].c;
}
sort (ALL (tmp), cmpA);
int m = 0, cnt = 0;
for (int i = 0; i &lt; n; i++) {
if (i &amp;&amp; tmp[i] == tmp[i - 1]) {
a[m].cnt++;
}
else {
m++;
a[m].a = tmp[i].a;
a[m].b = tmp[i].b;
a[m].c = tmp[i].c;
a[m].cnt = 1;
} }
bit.init (C);
CDQ (1, m);
for (int i = 1; i &lt;= m; i++) ans[a[i].res + a[i].cnt - 1] += a[i].cnt;
for (int i = 0; i &lt; n; i++) cout &lt;&lt; ans[i] &lt;&lt; "\n"; } signed main() {
// ios::sync_with_stdio(0);
// cin.tie(0);
int t = 1;
//cin &gt;&gt; t;
while (t--) {
solve();
}
} </code></pre>

Zerojudge c571.三維偏序 <p>給 \(n\) 個三維空間的點 \((x,y,z)\)，問對於第 \(i\) 個點，有幾個 \(j\) 滿足 \(x_j&gt;x_i,y_j&gt;y_i,z_j&gt;z_i\)</p> code <pre><code>#include &lt;bits/stdc++.h&gt;
#define int long long
#define pii pair&lt;int, int&gt;
#define pb push_back
#define mk make_pair
#define F first
#define S second
#define ALL(x) x.begin(), x.end()
#define lowbit(x) (x &amp; (-x))
using namespace std;
const int INF = 2e18;
const int maxn = 3e5 + 5;
const int M = 1e9 + 7;
struct triple {
int x, y, z, id;
};
struct BIT {
int n;
vector&lt;int&gt; bit;
void init (int _n) {
n = _n;
bit.resize (n + 1);
}
void add (int x, int d) {
x++;
while (x &gt; 0) {
bit[x] += d;
x -= lowbit (x);
}
}
int query (int x) {
x++;
int ret = 0;
while (x &lt;= n) {
ret += bit[x];
x += lowbit (x);
}
return ret;
}
}bit;
bool cmpX (triple &amp;A, triple &amp;B) {
if (A.x != B.x) return A.x &lt; B.x;
if (A.y != B.y) return A.y &gt; B.y;
return A.z &gt; B.z;
}
bool cmpY (triple &amp;A, triple &amp;B) {
if (A.y != B.y) return A.y &gt; B.y;
return A.z &gt; B.z;
}
int n;
int ans[maxn];
void solve (int l, int r, vector&lt;triple&gt; &amp;a) {
int mid = (l + r) / 2;
if (l == r) return;
vector&lt;triple&gt; aLeft, aRight;
for (auto [x, y ,z, id] : a) {
if (x &lt;= mid) aLeft.pb ({x, y, z, id});
else aRight.pb ({x, y, z, id});
}
solve (l, mid, aLeft); solve (mid + 1, r, aRight);
sort (ALL (aLeft), cmpY); sort (ALL (aRight), cmpY);
int i = 0, j = 0;
while (i &lt; aLeft.size ()) {
while (j &lt; aRight.size () &amp;&amp; aRight[j].y &gt; aLeft[i].y) {
bit.add (aRight[j].z, 1);
j++;
}
ans[aLeft[i].id] += bit.query (aLeft[i].z + 1);
i++;
}
for (int k = 0; k &lt; j; k++) {
bit.add (aRight[k].z, -1);
}
}
vector&lt;triple&gt; a;
void init () {
cin &gt;&gt; n;
a.resize (n);
for (int i = 0; i &lt; n; i++) {
cin &gt;&gt; a[i].x &gt;&gt; a[i].y &gt;&gt; a[i].z;
a[i].id = i;
a[i].x--, a[i].y--, a[i].z--;
}
}
void work () {
sort (ALL (a), cmpX);
bit.init (n);
solve (0, n - 1, a);
for (int i = 0; i &lt; n; i++) {
cout &lt;&lt; ans[i] &lt;&lt; "\n";
}
} signed main() {
ios::sync_with_stdio(0);
cin.tie(0);
int t = 1;
//cin &gt;&gt; t;
while (t--) {
init();
work();
}
} </code></pre>

CSES Forest Queries II <p>在二維平面上，支持以下操作</p> <ul> <li> <p>支持在一個矩形區域內加一個數字</p> </li> <li> <p>每次詢問一個矩形區域的和</p> </li> </ul> 思路 <p>「詢問一個矩形區域的和」可以看做是四個詢問 \((x_i,y_i)\) 的數值總和</p> \[\small ans=sum(x_2,y_2)-sum(x_1-1,y_2)-sum(x_2,y_1-1)+sum(x_1-1,x_2-1)\] <p>那要怎麼維護操作先後順序呢 ? 我們可以多加一為 \(z\) 表示此操作的時間戳記，問題就變成</p> <p>給定一個 \((x_i,y_i,z_i)\) 詢問 \(\begin{cases}x_j \le x_i \\ y_j \le y_i \\ z_j \le z_i \end{cases}\) 的權值總和</p> code <pre><code>#include &lt;algorithm&gt;
#include &lt;cassert&gt;
#include &lt;iostream&gt;
#include &lt;utility&gt;
#include &lt;vector&gt;
#define int long long
#define pii pair&lt;int, int&gt;
#define pb push_back
#define mk make_pair
#define F first
#define S second
#define lowbit(x) (x &amp; (-x))
#define ALL(x) x.begin(), x.end()
using namespace std;
const int maxn = 3e5 + 5;
int n, q;
int ans[maxn], op[maxn];
int g[1005][1005], pre[1005][1005];
struct triple {
int a, b, c, cnt, x, id;
// (z, x, y), cnt, multiply, org qry idx
};
vector&lt;triple&gt; a;
int t = 0;
void add_event(int i, int j, int cnt, int x, int id) {
if (i &lt;= 0) return;
if (j &lt;= 0) return;
a.pb({t++, i, j, cnt, x, id});
}
int cmpA(const triple &amp;A, const triple &amp;B) {
if (A.a != B.a) return A.a &lt; B.a;
if (A.b != B.b) return A.b &lt; B.b;
return A.c &lt; B.c;
}
int cmpB(const triple &amp;A, const triple &amp;B) {
if (A.b != B.b) return A.b &lt; B.b;
return A.c &lt; B.c;
}
struct BIT {
vector&lt;int&gt; bit;
int n;
void init(int _n) {
n = _n;
bit.resize(n + 1);
}
void add(int x, int d) {
assert(x != 0);
while (x &lt;= n) {
bit[x] += d;
x += lowbit(x);
}
}
int query(int x) {
int ret = 0;
while (x &gt; 0) {
ret += bit[x];
x -= lowbit(x);
}
return ret;
}
} bit;
void CDQ(int l, int r) {
if (l == r) return;
// cout &lt;&lt; l &lt;&lt; ' ' &lt;&lt; r &lt;&lt; endl;
int mid = (l + r) / 2;
CDQ(l, mid);
CDQ(mid + 1, r);
// sort(a.begin() + l, a.begin() + mid + 1, cmpB);
// sort(a.begin() + mid + 1, a.begin() + r + 1, cmpB);
int i = l;
for (int j = mid + 1; j &lt;= r; j++) {
while (i &lt;= mid &amp;&amp; a[i].b &lt;= a[j].b) {
bit.add(a[i].c, a[i].cnt);
i++;
}
ans[a[j].id] += a[j].x * bit.query(a[j].c);
}
for (int k = l; k &lt; i; k++) {
bit.add(a[k].c, -a[k].cnt);
}
inplace_merge(a.begin() + l, a.begin() + mid + 1, a.begin() + r + 1, cmpB);
}
void solve() {
cin &gt;&gt; n &gt;&gt; q;
for (int i = 1; i &lt;= n; i++) {
for (int j = 1; j &lt;= n; j++) {
char c;
cin &gt;&gt; c;
if (c == '*') {
g[i][j] = 1;
pre[i][j]++;
}
}
}
for (int i = 1; i &lt;= n; i++) {
for (int j = 1; j &lt;= n; j++) {
pre[i][j] =
pre[i][j] + pre[i - 1][j] + pre[i][j - 1] - pre[i - 1][j - 1];
// cout &lt;&lt; "i:" &lt;&lt; i &lt;&lt; ",j:" &lt;&lt; j &lt;&lt; ",pre:" &lt;&lt; pre[i][j] &lt;&lt; "\n";
}
}
for (int cs = 1; cs &lt;= q; cs++) {
cin &gt;&gt; op[cs];
if (op[cs] == 1) {
int i, j;
cin &gt;&gt; i &gt;&gt; j;
if (g[i][j] == 1) {
add_event(i, j, -1, 0, 0);
g[i][j] = 0;
} else {
add_event(i, j, +1, 0, 0);
g[i][j] = 1;
}
} else {
int i1, i2, j1, j2;
cin &gt;&gt; i1 &gt;&gt; j1 &gt;&gt; i2 &gt;&gt; j2;
i1--, j1--;
add_event(i2, j2, 0, +1, cs);
add_event(i1, j2, 0, -1, cs);
add_event(i2, j1, 0, -1, cs);
add_event(i1, j1, 0, +1, cs);
ans[cs] += pre[i2][j2] - pre[i1][j2] - pre[i2][j1] + pre[i1][j1];
}
}
sort(ALL(a), cmpA);
bit.init(1024);
CDQ(0, (int)a.size() - 1);
for (int i = 1; i &lt;= q; i++) {
if (op[i] == 1) continue;
cout &lt;&lt; ans[i] &lt;&lt; '\n';
}
}
signed main() {
ios::sync_with_stdio(0);
cin.tie(0);
solve();
}
</code></pre> <ul> <li>類似題 : APIO 2019 路燈</li> </ul>

洛谷 P3834 - 【模板】可持久化线段树 2 <p>給長度為 \(n\) 的序列，\(q\) 筆詢問</p> <ul> <li>\(\text{query(}a_l\sim a_r,k):\) 回答 \(a_l\sim a_r\) 中第 \(k\) 小的數值是多少</li> </ul> <p>\(n,q\le 2\times 10^5,|a_i|\le 10^9\)</p> code <pre><code>#include &lt;bits/stdc++.h&gt;
#define int long long
#define pii pair&lt;int, int&gt;
#define pb push_back
#define mk make_pair
#define F first
#define S second
#define ALL(x) x.begin(), x.end()
#define lowbit(x) (x &amp; (-x))
using namespace std;
const int INF = 2e18;
const int maxn = 3e5 + 5;
const int M = 1e9 + 7;
struct BIT {
int n;
vector&lt;int&gt; bit;
void init (int _n) {
n = _n;
bit.resize (n + 1);
}
void add (int x, int d) {
while (x &lt;= n) {
bit[x] += d;
x += lowbit (x);
}
}
int query (int x) {
int ret = 0;
while (x &gt; 0) {
ret += bit[x];
x -= lowbit (x);
}
return ret;
}
} bit;
struct qry {
int l, r, k, id;
};
int n, q;
int arr[maxn], a[maxn], ans[maxn];
void solve (int l, int r, vector&lt;int&gt; &amp;idx, vector&lt;qry&gt; &amp;q) {
if (l == r) {
for (auto [ql, qr, k, id] : q) {
ans[id] = l;
}
return;
}
int mid = (l + r) / 2;
vector&lt;int&gt; iLeft, iRight;
for (auto id : idx) {
if (a[id] &lt;= mid) {
bit.add (id, 1);
iLeft.pb (id);
}
else iRight.pb (id);
}
vector&lt;qry&gt; qLeft, qRight;
for (auto [ql, qr, k, id] : q) {
int t = bit.query (qr) - bit.query (ql - 1);
if (k &lt;= t) {
qLeft.pb ({ql, qr, k, id});
}
else {
qRight.pb ({ql, qr, k - t, id});
}
}
for (auto id : idx) {
if (a[id] &lt;= mid) bit.add (id, -1);
}
vector&lt;int&gt;().swap (idx);
vector&lt;qry&gt;().swap (q);
solve (l, mid, iLeft, qLeft);
solve (mid + 1, r, iRight, qRight);
}
