d.resize (unique (ALL (d)) - d.begin ());
vector&lt;int&gt; idx;
for (int i = 1; i &lt;= n; i++) {
a[i] = lower_bound (ALL (d), arr[i]) - d.begin () + 1;
}
for (int i = 1; i &lt;= n; i++) {
idx.pb (i);
}
vector&lt;qry&gt; qry;
for (int i = 1; i &lt;= q; i++) {
int l, r, k;
cin &gt;&gt; l &gt;&gt; r &gt;&gt; k;
qry.pb ({l, r, k, i});
}
bit.init (n);
solve (1, d.size (), idx, qry);
for (int i = 1; i &lt;= q; i++) {
