洛谷 P2617 - Dynamic Rankings <p>給長度為 \(n\) 的序列，\(q\) 筆詢問</p> <ul> <li>\(\text{query(}a_l\sim a_r,k):\) 回答 \(a_l\sim a_r\) 中第 \(k\) 小的數值是多少</li> <li>\(\text{modify(}a_i,x):\) 將 \(a_i\) 的數值改成 \(x\)</li> </ul> <p>\(n,q\le 2\times 10^5\)</p> 思路 <ol> <li>把原先 \(a_i\) 的貢獻給扣除</li> <li>將 \(x\) 的貢獻加入</li> </ol> code <pre><code>#include &lt;bits/stdc++.h&gt;
#define int long long
#define pii pair&lt;int, int&gt;
#define pb push_back
#define mk make_pair
#define lowbit(x) (x &amp; (-x))
#define F first
#define S second
#define ALL(x) x.begin(), x.end()
using namespace std;
using PQ = priority_queue&lt;int, vector&lt;int&gt;, greater&lt;int&gt;&gt;;
const int INF = 2e18;
const int maxn = 3e5 + 5;
const int M = 1e9 + 7;
int n, m, cnt = 0, tot = 0;;
int a[maxn], ans[maxn];
struct query {
int type, x, y, k, id;
// 0, l, r, k, qry id
// 1, index, number, 1/-1 add or del, qry id
};
query q1[2 * maxn], q2[2 * maxn], q[2 * maxn];
query qry[maxn];
struct BIT {
vector&lt;int&gt; bit;
void init () {
bit.resize (n + 1);
}
void add (int x, int d) {
while (x &lt;= n) {
bit[x] += d;
x += lowbit (x);
}
}
int query (int x) {
int ret = 0;
while (x &gt; 0) {
ret += bit[x];
x -= lowbit (x);
}
return ret;
}
} bit;
void divide (int l, int r, int qL, int qR) {
if (l &gt; r || qL &gt; qR) return;
if (l == r) {
for (int i = qL; i &lt;= qR; i++) {
if (q[i].type == 0) {
ans[q[i].id] = l;
} }
return;
}
int mid = (l + r) / 2;
int cnt1 = 0, cnt2 = 0;
for (int i = qL; i &lt;= qR; i++) {
if (q[i].type == 0) {
int t = bit.query (q[i].y) - bit.query (q[i].x - 1);
if (q[i].k &lt;= t) q1[++cnt1] = q[i];
else q[i].k -= t, q2[++cnt2] = q[i];
} else {
if (q[i].y &lt;= mid) {
bit.add (q[i].x, q[i].k); // q[i].x
q1[++cnt1] = q[i];
}
else q2[++cnt2] = q[i];
}
}
// undo
for (int i = 1; i &lt;= cnt1; i++) if (q1[i].type == 1) bit.add (q1[i].x, -q1[i].k);
for (int i = 1; i &lt;= cnt1; i++) q[qL + i - 1] = q1[i];
for (int i = 1; i &lt;= cnt2; i++) q[qL + cnt1 + i - 1] = q2[i];
divide (l, mid, qL, qL + cnt1 - 1);
divide (mid + 1, r, qL + cnt1, qR);
}
void solve () {
cin &gt;&gt; n &gt;&gt; m;
int x;
for (int i = 1; i &lt;= n; i++) {
cin &gt;&gt; x;
a[i] = x;
q[++cnt] = {1, i, a[i], 1, -1};
}
for (int i = 1; i &lt;= m; i++) {
int x, y, k;
char type;
cin &gt;&gt; type;
if(type == 'Q') {
cin &gt;&gt; x &gt;&gt; y &gt;&gt; k;
q[++cnt] = 0, x, y, k, ++tot};
}
else {
cin &gt;&gt; x &gt;&gt; y;
q[++cnt] = {1, x, a[x], -1, 0};
q[++cnt] = {1, x, a[x] = y, 1, 0};
}
}
bit.init ();
divide (-2e9, 2e9, 1, cnt);
for (int i = 1; i &lt;= tot; i++) {
cout &lt;&lt; ans[i] &lt;&lt; "\n";
}
} signed main() {
// ios::sync_with_stdio(0);
// cin.tie(0);
int t = 1;
//cin &gt;&gt; t;
while (t--) {
solve();
}
} </code></pre>

Atcoder AGC002 D - Stamp Rally <p>給 \(n\) 點 \(m\) 邊無向圖，邊的編號 \(1 \sim m\)</p> <p>\(q\) 筆詢問 \(x, y, z\)</p> <p>回答從 \(x\) 點出發和從 \(y\) 點走的「點集聯集大小」至少是 \(z\) 的最大「邊」編號最小值</p> <ul> <li>\(n,m,q \le 10^5\)</li> </ul> 思路 <p>暴力作法</p> <p>我們二分搜 \(\displaystyle \text{mid}=\frac{l+r}{2}=t\) </p> <p>檢查如果只走 \(\le t\) 的邊 : </p> <ul> <li> <p>\(x\) 和 \(y\) 是否在同一個連通塊</p> </li> <li> <p>連通塊大小是否 \(\ge z\)</p> </li> </ul> <p>複雜度 : \(O(q\times (n+m))\)</p> <p>這邊我們引入一個技巧，下面的方法會用到</p> <p>技巧詳見 : 最大邊最小化生成樹 法3</p> <p>方法一 : 把 graph 拆半，兩個子問題圖都只有本來的一半</p> <ul> <li> <p>\(ans \le t\) 少一半的 edge</p> </li> <li> <p>\(ans &gt; t\) 少一半的 edge，縮點</p> </li> </ul> <p>時間複雜度 : \(O(m \log m)\)</p> <p>空間複雜度 : \(O(m)\)1</p> code <pre><code>#include &lt;iostream&gt;
