using namespace std;
struct Edge {
int u, v, w;
};
struct qry {
int x, y, z, id;
};
struct Graph {
public:
Graph(int n) : n(n) {
par = vector&lt;int&gt;(n);
sz = vector&lt;int&gt;(n, 1);
for (int i = 0; i &lt; n; i++) {
par[i] = i;
}
}
void add_edge(const Edge&amp; e) {
int u = find(e.u), v = find(e.v);
if (u == v) return;
par[u] = v;
sz[v] += sz[u];
sz[u] = 0;
}
bool check(const qry&amp; q) {
int u = find(q.x), v = find(q.y);
if (u != v) {
return sz[u] + sz[v] &gt;= q.z;
}
return sz[u] &gt;= q.z;
}
int find(int x) {
if (par[x] == x) return x;
return par[x] = find(par[x]);
}
int size() {
return n;
}
vector&lt;int&gt; sz;
private:
int n;
vector&lt;int&gt; par;
};
const int maxn = 3e5 + 5;
