void shrink(vector&lt;Edge&gt;&amp; edge, vector&lt;qry&gt;&amp; q, Graph&amp; G) {
// query 有用到的 node 才要存
// 相同 CC 的點，要變成同樣編號
// 新圖的點邊號是 0 ~ (k-1)
