for (auto [x, y, z, id] : q) {
need[G.find(x)] = true;
need[G.find(y)] = true;
}
for (auto [u, v, w] : edge) {
need[G.find(u)] = true;
need[G.find(v)] = true;
}
vector&lt;int&gt; new_id(n, -1);
vector&lt;int&gt; sz;
int k = 0;
for (int i = 0; i &lt; n; i++) {
if (need[i]) {
new_id[i] = k++;
sz.push_back(G.sz[i]);
}
}
for (auto&amp; [x, y, z, id] : q) {
x = new_id[G.find(x)];
y = new_id[G.find(y)];
}
for (auto&amp; [u, v, w] : edge) {
u = new_id[G.find(u)];
v = new_id[G.find(v)];
}
