G.add_edge({u, v, w});
eLeft.pb({u, v, w});
} else {
eRight.pb({u, v, w});
}
}
vector&lt;qry&gt; qLeft, qRight;
for (auto query : q) {
if (G.check(query)) {
qLeft.pb(query);
} else {
qRight.pb(query);
}
}
solve(el, emid, eLeft, qLeft, gLeft);
solve(emid + 1, er, eRight, qRight, gRight);
}
int n, m, q;
void init() {
