LOJ #3334. 「BalticOI 2020」小丑 <p>給你 \(n\) 點 \(m\) 邊的無向圖，邊以 \(1\sim m\) 編號，有 \(q\) 筆詢問，第 \(i\) 筆詢問問</p> <ul> <li>移除編號在 \([l_i,r_i]\) 內的邊是否可以讓圖沒有奇環</li> </ul> <p>\(n,m,q\le 2\times 10^5\)</p> 思路 <p>ans[i] 表示 </p> <ul> <li> <p>移除 [i, ans[i] - 1] 有 odd cycle</p> </li> <li> <p>移除 [i, ans[i]] 沒 odd cycle</p> </li> </ul> <p>對於每個 i，二分搜 ans[i]，使 [i, ans[i]] 沒 odd cycle</p> <p>再來要定義上界下界</p> <p>下界的部分有可能只移除第 i 個邊就沒有 odd cycle 了</p> <p>上界的部分就要保證移除 [i, m - 1] 就沒有 odd cycle</p> <p>所以我們找到第一個 prefix[0, qr] 滿足 :</p> <ul> <li> <p>只用 [0, qr - 1] 的邊沒有 odd cycle</p> </li> <li> <p>只用 [0, qr] 的邊有 odd cycle</p> </li> </ul> <p>i &gt; qr 的部分不管移除多少個邊都還是會有 odd cycle</p> code <pre><code>#include &lt;bits/stdc++.h&gt;
#define int long long
#define pii pair&lt;int, int&gt;
#define pb push_back
#define mk make_pair
#define F first
#define S second
#define ALL(x) x.begin(), x.end()
using namespace std;
const int INF = 2e18;
const int maxn = 3e5 + 5;
const int M = 1e9 + 7;
struct Edge {
int u, v;
};
struct Graph {
Graph (int n) : n(n) {
sz = vector&lt;int&gt;(n, 1);
par = vector&lt;int&gt;(n);
dis = vector&lt;int&gt;(n);
cnt = 0;
for (int i = 0; i &lt; n; i++) {
par[i] = i;
}
}
void add_edge (const Edge &amp;e) {
auto [x, disx] = find (e.u);
auto [y, disy] = find (e.v);
if (x == y) {
// if (disx == disy) =&gt; odd cycle
cnt += (disx == disy);
stk.push ({-1, (disx == disy)});
return;
}
if (sz[x] &lt; sz[y]) swap (x, y);
sz[x] += sz[y]; par[y] = x; dis[y] = disx ^ disy ^ 1;
stk.push ({x, y});
}
void undo () {
auto [x, y] = stk.top ();
stk.pop ();
if (x == -1) {
cnt -= y;
return;
}
sz[x] -= sz[y]; par[y] = y; dis[y] = 0;
}
bool check () {
// return : 有沒有 odd cycle
return (cnt &gt; 0);
}
private :
int n, cnt;
vector&lt;int&gt; sz;
vector&lt;int&gt; par;
vector&lt;int&gt; dis;
stack&lt;pii&gt; stk;
pii find (int x) {
if (par[x] == x) return {x, 0};
else {
auto [fa, d] = find (par[x]);
return {fa, d ^ dis[x]};
} }
};
int n, m, q;
int ans[maxn];
vector&lt;Edge&gt; edges;
void solve (Graph &amp;g, int el, int er, int ql, int qr) {
// [0, ql - 1] and [er + 1, m - 1] 都已加入 g 
if (ql &gt; qr) return;
if (el == er) {
for (int i = ql; i &lt;= qr; i++) {
ans[i] = el;
}
return;
}
int emid = (el + er) / 2, qmid = min (emid, qr);
for (int i = emid + 1; i &lt;= er; i++) {
g.add_edge (edges[i]);
}
int cnt = 0;
for (int i = ql; i &lt;= min (emid, qr); i++) {
if (i &gt; ql) g.add_edge (edges[i - 1]), cnt++;
if (g.check ()) {
// 移除 [i, emid] 有 odd cycle
// 移除 [i - 1, emid] 沒 odd cycle
qmid = i - 1;
break;
}
}
while (cnt--) {
g.undo ();
}
solve (g, el, emid, ql, qmid); // [0, ql - 1] [emid + 1, m - 1]
for (int i = emid + 1; i &lt;= er; i++) {
g.undo ();
}
for (int i = ql; i &lt;= qmid; i++) {
g.add_edge (edges[i]);
}
solve (g, emid + 1, er, qmid + 1, qr); // [0, qmid] [er + 1, m - 1]
for (int i = ql; i &lt;= qmid; i++) {
g.undo ();
}
}
void init () {
cin &gt;&gt; n &gt;&gt; m &gt;&gt; q;
int u, v;
for (int i = 0; i &lt; m; i++) {
cin &gt;&gt; u &gt;&gt; v;
u--, v--;
edges.pb ({u, v});
}
}
// 找到最小的 ans[i], 使移除 [i, ans[i]] 沒 odd cycle
// 移除 [i, ans[i] - 1] 有 odd cycle
// 移除 [i, ans[i]] 沒 odd cycle
void build () {
// 使得 ans[i] 有上界
// TODO : 找到第一個 i 使得 用 [0, i] 的 edge 有 odd cycle
Graph tmp(n);
int ql = 0, qr = m;
for (int i = 0; i &lt; m; i++) {
tmp.add_edge (edges[i]);
if (tmp.check ()) {
qr = i;
break;
} }
if (qr == m) {
for (int i = 0; i &lt; m; i++) {
ans[i] = i;
}
return;
}
for (int i = qr + 1; i &lt; m; i++) {
ans[i] = m;
}
Graph g(n);
solve (g, 0, m - 1, ql, qr);
}
void work () {
build ();
while (q--) {
int l, r;
cin &gt;&gt; l &gt;&gt; r;
l--, r--;
if (ans[l] &lt;= r) cout &lt;&lt; "NO\n";
else cout &lt;&lt; "YES\n";
}
} signed main() {
// ios::sync_with_stdio(0);
// cin.tie(0);
int t = 1;
//cin &gt;&gt; t;
while (t--) {
init ();
work();
}
}
