TIOJ 1919.王老先生 <p>給你 \(N\) 個人的目標金額 \(V_1,V_2,\ldots ,V_n\)，和 \(M\) 塊農地 \(a_1,a_2\ldots ,a_M\)，代表第 \(i\) 塊農地的主人</p> <p>\(Q\) 次對區間 \([L,R]\) 的農地加上 \(C\)，如果有人在這個區間內擁有多個土地，他還是只會被加到一次 \(C\)，問每個人分別在哪次操作後達到目標，或是沒有達到</p> <p>\(1\le N,M,Q\le 10^5,1\le V_i,C_i\le 10^9\)</p> 提示 <p>如果只有 \(1\) 個主人</p> 思路 <p>對於每個人二分搜哪一次操作後達到目標</p> <p>那對於每個人要怎麼計算一堆 query 的貢獻呢 ?</p> <p>對於 \(i\) 支配的每塊地，我們考慮他後面第一個出現的位置</p> <p>我們把這塊地的 index 叫做 \(i\)，後面第一個出現的 index 叫做 \(j\)</p> <p>那就是要計算符合 \(\begin{cases}L\le i \\ j &gt; R \\ i \le R\end{cases}\) 的 \([L,R]\) 的貢獻總和</p> <p>就是一個二維平面問題，我們只要將第一維排序，第二維使用 BIT 即可</p> <p> </p> code <pre><code>#include &lt;bits/stdc++.h&gt;
#define int long long
#define pii pair&lt;int, int&gt;
#define pb push_back
#define mk make_pair
#define F first
#define S second
#define ALL(x) x.begin(), x.end()
#define lowbit(x) (x &amp; (-x))
using namespace std;
const int INF = 2e18;
const int maxn = 3e5 + 5;
const int M = 1e9 + 7;
struct opr {
int l, r, c;
bool operator&lt;(const opr &amp;other) {
return l &lt; other.l;
}
};
struct qry {
// farmer id, need how much
int id, goal;
};
struct BIT {
BIT (int n) : n(n) {
bit.resize (n + 1);
}
void add (int x, int d) {
while (x &lt;= n) {
bit[x] += d;
x += lowbit (x);
}
}
int query (int x) {
int ret = 0;
while (x &gt; 0) {
ret += bit[x];
x -= lowbit (x);
}
return ret;
}
bool clean () {
for (int i = 1; i &lt;= n; i++) {
if (bit[i]) return false;
}
return true;
}
private :
int n;
vector&lt;int&gt; bit;
};
int n, m, q;
vector&lt;int&gt; G[maxn];
vector&lt;opr&gt; operation;
vector&lt;qry&gt; queries;
int nxt[maxn], a[maxn], ans[maxn];
void solve (BIT &amp;bit, int el, int er, vector&lt;qry&gt; &amp;q) {
// 在 [el, er] 的這些操作中，我在哪個操作可以達到目標
if (el == er) {
for (auto [id, goal] : q) {
ans[id] = el;
}
return;
}
int emid = (el + er) / 2;
vector&lt;opr&gt; op(operation.begin () + el - 1, operation.begin () + emid);
sort (ALL (op));
vector&lt;pii&gt; query;
vector&lt;int&gt; cost;
int cnt = 0;
for (auto &amp;[id, goal] : q) {
for (auto i : G[id]) {
query.pb ({i, cnt});
}
cnt++;
}
cost.resize (cnt);
sort (ALL (query));
int ptr = 0;
for (auto [i, idx] : query) {
int j = nxt[i];
while (ptr &lt; op.size () &amp;&amp; op[ptr].l &lt;= i) {
bit.add (op[ptr].r, op[ptr].c);
ptr++;
} if (j == 0) {
int t = bit.query (m) - bit.query (i - 1);
cost[idx] += t;
}
else {
int t = bit.query (j - 1) - bit.query (i - 1);
cost[idx] += t;
}
}
cnt = 0;
vector&lt;qry&gt; qLeft, qRight;
for (auto &amp;[id, goal] : q) {
if (goal &lt;= cost[cnt]) {
qLeft.pb ({id, goal});
} else {
qRight.pb ({id, goal - cost[cnt]});
} cnt++;
}
for (int i = 0; i &lt; ptr; i++) {
bit.add (op[i].r, -op[i].c);
}
vector&lt;pii&gt;().swap (query);
vector&lt;int&gt;().swap (cost);
vector&lt;opr&gt;().swap (op);
vector&lt;qry&gt;().swap (q);
solve (bit, el, emid, qLeft);
solve (bit, emid + 1, er, qRight);
}
void init () {
cin &gt;&gt; n &gt;&gt; m &gt;&gt; q;
for (int i = 1; i &lt;= m; i++) {
cin &gt;&gt; a[i];
if (G[a[i]].size()) nxt[G[a[i]].back ()] = i;
G[a[i]].pb (i);
}
for (int i = 1; i &lt;= n; i++) {
int x;
cin &gt;&gt; x;
queries.pb ({i, x});
}
for (int i = 1; i &lt;= q; i++) {
int l, r, c;
cin &gt;&gt; l &gt;&gt; r &gt;&gt; c;
operation.pb ({l, r, c});
}
}
void work () {
q++;
operation.pb ({1, m, (int)2e9});
BIT bit(m);
solve (bit, 1, q, queries);
for (int i = 1; i &lt;= n; i++) {
if (ans[i] == q) cout &lt;&lt; -1 &lt;&lt; "\n";
else cout &lt;&lt; ans[i] &lt;&lt; "\n";
}
} signed main() {
// ios::sync_with_stdio(0);
// cin.tie(0);
int t = 1;
//cin &gt;&gt; t;
while (t--) {
init();
work();
}
} </code></pre>

